import { useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Bell, MessageSquare } from "lucide-react";
import { isUnauthorizedError } from "@/lib/authUtils";
import type { Broadcast } from "@shared/schema";
import { format } from "date-fns";

export default function TutorUpdates() {
  const { isAuthenticated, isLoading: authLoading } = useAuth();
  const { toast } = useToast();

  const {
    data: broadcasts,
    isLoading,
    error,
  } = useQuery<Broadcast[]>({
    queryKey: ["/api/broadcasts"],
    enabled: isAuthenticated && !authLoading,
  });

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [isAuthenticated, authLoading, toast]);

  useEffect(() => {
    if (error && isUnauthorizedError(error)) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [error, toast]);

  if (authLoading || isLoading) {
    return (
      <DashboardLayout>
        <div className="space-y-6">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-64" />
        </div>
      </DashboardLayout>
    );
  }

  const getRoleColor = (role: string) => {
    switch (role) {
      case "coo":
        return "bg-amber-100 text-amber-800 border-amber-200";
      case "td":
        return "bg-purple-100 text-purple-800 border-purple-200";
      default:
        return "bg-gray-100 text-gray-800 border-gray-200";
    }
  };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <h1 className="text-2xl md:text-3xl font-bold tracking-tight">Updates & Announcements</h1>

        <Card className="border">
          <div className="p-6 border-b">
            <div className="flex items-center gap-2">
              <Bell className="w-5 h-5 text-primary" />
              <h2 className="text-lg font-semibold">All Updates</h2>
            </div>
          </div>
          <div className="divide-y max-h-[600px] overflow-y-auto">
            {!broadcasts || broadcasts.length === 0 ? (
              <div className="p-12 text-center">
                <MessageSquare className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
                <p className="text-muted-foreground">No updates yet</p>
              </div>
            ) : (
              broadcasts.map((broadcast) => (
                <div
                  key={broadcast.id}
                  className="p-6 space-y-3 hover-elevate"
                  data-testid={`broadcast-${broadcast.id}`}
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-2">
                        <Badge
                          className={`${getRoleColor(broadcast.senderRole)} border font-semibold uppercase tracking-wide text-2xs px-2 py-0.5`}
                        >
                          {broadcast.senderRole === "coo"
                            ? "COO"
                            : broadcast.senderRole === "td"
                            ? "TD"
                            : "System"}
                        </Badge>
                        <span className="text-sm text-muted-foreground">
                          {format(new Date(broadcast.createdAt), "MMM d, yyyy 'at' h:mm a")}
                        </span>
                      </div>
                      <p className="leading-relaxed whitespace-pre-wrap">{broadcast.message}</p>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </Card>
      </div>
    </DashboardLayout>
  );
}

