import { DashboardLayout } from "@/components/layout/dashboard-layout";

export default function COODashboard() {
  const { toast } = useToast();
  const [showPodForm, setShowPodForm] = useState(false);
  const [podName, setPodName] = useState("");

  // Fetch all pods
  const { data: pods = [], isLoading: podsLoading } = useQuery<any[]>({
    queryKey: ["/api/coo/pods"],
  });

  // Fetch all TDs
  const { data: tds = [], isLoading: tdsLoading } = useQuery<any[]>({
    queryKey: ["/api/coo/tds"],
  });

  // Fetch all role permissions
  const { data: rolePermissions = [], isLoading: permissionsLoading } = useQuery<any[]>({
    queryKey: ["/api/coo/role-permissions"],
  });

  // Create pod mutation
  const createPodMutation = useMutation({
    mutationFn: async (podName: string) => {
      return await apiRequest("POST", "/api/coo/pods", { 
        podName, 
        podType: "training", 
        phase: "foundation", 
        status: "active" 
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/coo/pods"] });
      toast({ title: "Pod created successfully!" });
      setPodName("");
      setShowPodForm(false);
    },
    onError: () => {
      toast({ title: "Failed to create pod", variant: "destructive" });
    },
  });

  // Add TD email mutation - no longer used after UI removal

  // Assign TD to pod mutation
  const assignTDMutation = useMutation({
    mutationFn: async ({ tdId, podId }: { tdId: string; podId: string }) => {
      return await apiRequest("POST", "/api/coo/assign-td", { 
        tdId, 
        podId 
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/coo/tds"] });
      queryClient.invalidateQueries({ queryKey: ["/api/coo/pods"] });
      toast({ title: "TD assigned to pod!" });
    },
    onError: () => {
      toast({ title: "Failed to assign TD", variant: "destructive" });
    },
  });

  return (
    <DashboardLayout>
      <div className="space-y-8">
        {/* Pods Section */}
        <section>
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-2xl font-bold">Training Pods</h2>
            <Button
              onClick={() => setShowPodForm(!showPodForm)}
              data-testid="button-create-pod"
            >
              <Plus className="w-4 h-4 mr-2" />
              Create Pod
            </Button>
          </div>

          {showPodForm && (
            <Card className="mb-6">
              <CardHeader>
                <CardTitle>Create New Pod</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  <div>
                    <Label htmlFor="podName">Pod Name</Label>
                    <Input
                      id="podName"
                      value={podName}
                      onChange={(e) => setPodName(e.target.value)}
                      placeholder="e.g., Foundation Pod Alpha"
                      data-testid="input-pod-name"
                    />
                  </div>
                  <div className="flex gap-3">
                    <Button
                      onClick={() => podName && createPodMutation.mutate(podName)}
                      disabled={!podName || createPodMutation.isPending}
                      data-testid="button-submit-pod"
                    >
                      Create Pod
                    </Button>
                    <Button variant="ghost" onClick={() => setShowPodForm(false)}>
                      Cancel
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          )}

          {podsLoading ? (
            <p className="text-muted-foreground">Loading pods...</p>
          ) : pods.length === 0 ? (
            <Card>
              <CardContent className="py-8 text-center text-muted-foreground">
                No pods created yet. Create your first pod to get started!
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4 md:grid-cols-2">
              {pods.map((pod: any) => (
                <Card key={pod.id} data-testid={`card-pod-${pod.id}`}>
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                      <Users className="w-5 h-5 text-primary" />
                      {pod.pod_name || pod.podName}
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2 text-sm">
                      <p>
                        <span className="font-medium">Status:</span>{" "}
                        <span className="text-muted-foreground">{pod.status}</span>
                      </p>
                      <p>
                        <span className="font-medium">Type:</span>{" "}
                        <span className="text-muted-foreground">{(pod as any).pod_type || pod.podType}</span>
                      </p>
                      <p>
                        <span className="font-medium">Phase:</span>{" "}
                        <span className="text-muted-foreground">{pod.phase}</span>
                      </p>
                      <p>
                        <span className="font-medium">TD Assigned:</span>{" "}
                        <span className="text-muted-foreground">
                          {((pod as any).td_id || pod.tdId) ? "Yes" : "No"}
                        </span>
                      </p>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </section>

        {/* Territory Directors Section */}
        <section>
          <h2 className="text-2xl font-bold mb-6">Territory Directors</h2>

          {tdsLoading ? (
            <p className="text-muted-foreground">Loading TDs...</p>
          ) : tds.length === 0 ? (
            <Card>
              <CardContent className="py-8 text-center text-muted-foreground">
                No Territory Directors yet.
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4">
              {tds.map((td: any) => (
                <Card key={td.id} data-testid={`card-td-${td.id}`}>
                  <CardContent className="py-4">
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="font-medium">{td.name || td.email}</p>
                        <p className="text-sm text-muted-foreground">{td.email}</p>
                      </div>
                      <div className="flex items-center gap-3">
                        {((td as any).assigned_pod_id || td.assignedPodId) ? (
                          <Badge className="bg-green-600 hover:bg-green-700" data-testid={`badge-assigned-${td.id}`}>
                            Assigned
                          </Badge>
                        ) : null}
                        <Select
                          value={((td as any).assigned_pod_id || td.assignedPodId) || ""}
                          onValueChange={(podId) => {
                            if (podId) {
                              assignTDMutation.mutate({ tdId: td.id, podId });
                            }
                          }}
                        >
                          <SelectTrigger className="w-[200px]" data-testid={`select-pod-${td.id}`}>
                            <SelectValue placeholder="Assign to pod..." />
                          </SelectTrigger>
                          <SelectContent>
                            {pods.map((pod: any) => (
                              <SelectItem key={pod.id} value={pod.id}>
                                {pod.pod_name || pod.podName}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </section>
      </div>
    </DashboardLayout>
  );
}

