import { useEffect, useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { MessageSquare, Send } from "lucide-react";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { isUnauthorizedError } from "@/lib/authUtils";

export default function COOBroadcast() {
  const { isAuthenticated, isLoading: authLoading } = useAuth();
  const { toast } = useToast();
  const [message, setMessage] = useState("");
  const [visibility, setVisibility] = useState("all");

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [isAuthenticated, authLoading, toast]);

  const sendBroadcast = useMutation({
    mutationFn: async (data: { message: string; visibility: string }) => {
      await apiRequest("POST", "/api/coo/broadcast", {
        message: data.message,
        visibility: data.visibility,
        senderRole: "coo",
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/broadcasts"] });
      setMessage("");
      setVisibility("all");
      toast({
        title: "Broadcast sent",
        description: "Your message has been sent to the selected audience.",
      });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to send broadcast. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!message.trim()) {
      toast({
        title: "Validation Error",
        description: "Please enter a message.",
        variant: "destructive",
      });
      return;
    }
    sendBroadcast.mutate({ message: message.trim(), visibility });
  };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <h1 className="text-2xl md:text-3xl font-bold tracking-tight">Broadcast Message</h1>

        <Card className="p-6 border">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="flex items-center gap-3 mb-6">
              <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center">
                <MessageSquare className="w-6 h-6 text-primary" />
              </div>
              <div>
                <h2 className="font-semibold text-lg">Send System-Wide Update</h2>
                <p className="text-sm text-muted-foreground">
                  Communicate important updates and announcements
                </p>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="visibility">Audience *</Label>
              <Select value={visibility} onValueChange={setVisibility}>
                <SelectTrigger data-testid="select-visibility">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Everyone (All users)</SelectItem>
                  <SelectItem value="tutors">Tutors Only</SelectItem>
                  <SelectItem value="tds">Territory Directors Only</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="message">Message *</Label>
              <Textarea
                id="message"
                placeholder="Write your message here..."
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                className="min-h-48 resize-none"
                data-testid="input-message"
              />
              <p className="text-xs text-muted-foreground">
                This message will be visible to{" "}
                {visibility === "all"
                  ? "all users"
                  : visibility === "tutors"
                  ? "all tutors"
                  : "all territory directors"}
                .
              </p>
            </div>

            <Button
              type="submit"
              className="w-full gap-2"
              disabled={sendBroadcast.isPending}
              data-testid="button-send-broadcast"
            >
              <Send className="w-4 h-4" />
              {sendBroadcast.isPending ? "Sending..." : "Send Broadcast"}
            </Button>
          </form>
        </Card>
      </div>
    </DashboardLayout>
  );
}

client/src/components/ui/breadcrumb.tsx.content:
import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { ChevronRight, MoreHorizontal } from "lucide-react"

import { cn } from "@/lib/utils"

const Breadcrumb = React.forwardRef<
  HTMLElement,
  React.ComponentPropsWithoutRef<"nav"> & {
    separator?: React.ReactNode
  }
>(({ ...props }, ref) => <nav ref={ref} aria-label="breadcrumb" {...props} />)
Breadcrumb.displayName = "Breadcrumb"

const BreadcrumbList = React.forwardRef<
  HTMLOListElement,
  React.ComponentPropsWithoutRef<"ol">
>(({ className, ...props }, ref) => (
  <ol
    ref={ref}
    className={cn(
      "flex flex-wrap items-center gap-1.5 break-words text-sm text-muted-foreground sm:gap-2.5",
      className
    )}
    {...props}
  />
))
BreadcrumbList.displayName = "BreadcrumbList"

const BreadcrumbItem = React.forwardRef<
  HTMLLIElement,
  React.ComponentPropsWithoutRef<"li">
>(({ className, ...props }, ref) => (
  <li
    ref={ref}
    className={cn("inline-flex items-center gap-1.5", className)}
    {...props}
  />
))
BreadcrumbItem.displayName = "BreadcrumbItem"

const BreadcrumbLink = React.forwardRef<
  HTMLAnchorElement,
  React.ComponentPropsWithoutRef<"a"> & {
    asChild?: boolean
  }
>(({ asChild, className, ...props }, ref) => {
  const Comp = asChild ? Slot : "a"

  return (
    <Comp
      ref={ref}
      className={cn("transition-colors hover:text-foreground", className)}
      {...props}
    />
  )
})
BreadcrumbLink.displayName = "BreadcrumbLink"

const BreadcrumbPage = React.forwardRef<
  HTMLSpanElement,
  React.ComponentPropsWithoutRef<"span">
>(({ className, ...props }, ref) => (
  <span
    ref={ref}
    role="link"
    aria-disabled="true"
    aria-current="page"
    className={cn("font-normal text-foreground", className)}
    {...props}
  />
))
BreadcrumbPage.displayName = "BreadcrumbPage"

const BreadcrumbSeparator = ({
  children,
  className,
  ...props
}: React.ComponentProps<"li">) => (
  <li
    role="presentation"
    aria-hidden="true"
    className={cn("[&>svg]:w-3.5 [&>svg]:h-3.5", className)}
    {...props}
  >
    {children ?? <ChevronRight />}
  </li>
)
BreadcrumbSeparator.displayName = "BreadcrumbSeparator"

const BreadcrumbEllipsis = ({
  className,
  ...props
}: React.ComponentProps<"span">) => (
  <span
    role="presentation"
    aria-hidden="true"
    className={cn("flex h-9 w-9 items-center justify-center", className)}
    {...props}
  >
    <MoreHorizontal className="h-4 w-4" />
    <span className="sr-only">More</span>
  </span>
)
BreadcrumbEllipsis.displayName = "BreadcrumbElipssis"

export {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
  BreadcrumbEllipsis,
}

client/src/pages/tutor/academics.tsx.content:
import { useEffect, useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Skeleton } from "@/components/ui/skeleton";
import { Progress } from "@/components/ui/progress";
import { BookOpen, Plus, Target, TrendingUp, Edit, Trash2 } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { isUnauthorizedError } from "@/lib/authUtils";
import type { AcademicTracker } from "@shared/schema";

export default function TutorAcademics() {
  const { isAuthenticated, isLoading: authLoading } = useAuth();
  const { toast } = useToast();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    subject: "",
    targetMark: "",
    currentMark: "",
    strategyNotes: "",
  });

  const {
    data: subjects,
    isLoading,
    error,
  } = useQuery<AcademicTracker[]>({
    queryKey: ["/api/tutor/academics"],
    enabled: isAuthenticated && !authLoading,
  });

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [isAuthenticated, authLoading, toast]);

  useEffect(() => {
    if (error && isUnauthorizedError(error)) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [error, toast]);

  const createOrUpdate = useMutation({
    mutationFn: async (data: typeof formData) => {
      if (editingId) {
        await apiRequest("PUT", `/api/tutor/academics/${editingId}`, {
          ...data,
          targetMark: parseInt(data.targetMark),
          currentMark: data.currentMark ? parseInt(data.currentMark) : null,
        });
      } else {
        await apiRequest("POST", "/api/tutor/academics", {
          ...data,
          targetMark: parseInt(data.targetMark),
          currentMark: data.currentMark ? parseInt(data.currentMark) : null,
        });
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/tutor/academics"] });
      setDialogOpen(false);
      setEditingId(null);
      setFormData({ subject: "", targetMark: "", currentMark: "", strategyNotes: "" });
      toast({
        title: editingId ? "Subject updated" : "Subject added",
        description: "Your academic tracker has been updated successfully.",
      });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to save subject. Please try again.",
        variant: "destructive",
      });
    },
  });

  const deleteSubject = useMutation({
    mutationFn: async (id: string) => {
      await apiRequest("DELETE", `/api/tutor/academics/${id}`, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/tutor/academics"] });
      toast({
        title: "Subject removed",
        description: "The subject has been removed from your tracker.",
      });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to remove subject. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleEdit = (subject: AcademicTracker) => {
    setEditingId(subject.id);
    setFormData({
      subject: subject.subject,
      targetMark: subject.targetMark.toString(),
      currentMark: subject.currentMark?.toString() || "",
      strategyNotes: subject.strategyNotes || "",
    });
    setDialogOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.subject.trim() || !formData.targetMark) {
      toast({
        title: "Validation Error",
        description: "Please fill in all required fields.",
        variant: "destructive",
      });
      return;
    }
    createOrUpdate.mutate(formData);
  };

  if (authLoading || isLoading) {
    return (
      <DashboardLayout>
        <div className="space-y-6">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-40" />
          <Skeleton className="h-64" />
        </div>
      </DashboardLayout>
    );
  }

  const averageProgress =
    subjects && subjects.length > 0
      ? subjects.reduce((sum, s) => {
          const current = s.currentMark || 0;
          const progress = Math.min((current / s.targetMark) * 100, 100);
          return sum + progress;
        }, 0) / subjects.length
      : 0;

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="space-y-2">
            <h1 className="text-2xl md:text-3xl font-bold tracking-tight">Academic Tracker</h1>
            <p className="text-muted-foreground">Keep your own grades strong while helping others grow</p>
          </div>
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button
                className="gap-2"
                onClick={() => {
                  setEditingId(null);
                  setFormData({ subject: "", targetMark: "", currentMark: "", strategyNotes: "" });
                }}
                data-testid="button-add-subject"
              >
                <Plus className="w-4 h-4" />
                Add Subject
              </Button>
            </DialogTrigger>
            <DialogContent>
              <form onSubmit={handleSubmit}>
                <DialogHeader>
                  <DialogTitle>{editingId ? "Edit Subject" : "Add Subject"}</DialogTitle>
                  <DialogDescription>
                    Track your academic performance to ensure tutoring doesn't affect your
                    grades.
                  </DialogDescription>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div className="space-y-2">
                    <Label htmlFor="subject">Subject Name *</Label>
                    <Input
                      id="subject"
                      placeholder="e.g., Mathematics"
                      value={formData.subject}
                      onChange={(e) =>
                        setFormData({ ...formData, subject: e.target.value })
                      }
                      data-testid="input-subject"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="target">Target Mark *</Label>
                      <Input
                        id="target"
                        type="number"
                        min="0"
                        max="100"
                        placeholder="80"
                        value={formData.targetMark}
                        onChange={(e) =>
                          setFormData({ ...formData, targetMark: e.target.value })
                        }
                        data-testid="input-target-mark"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="current">Current Mark</Label>
                      <Input
                        id="current"
                        type="number"
                        min="0"
                        max="100"
                        placeholder="75"
                        value={formData.currentMark}
                        onChange={(e) =>
                          setFormData({ ...formData, currentMark: e.target.value })
                        }
                        data-testid="input-current-mark"
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="strategy">Strategy Notes</Label>
                    <Textarea
                      id="strategy"
                      placeholder="What are you doing to improve this subject?"
                      value={formData.strategyNotes}
                      onChange={(e) =>
                        setFormData({ ...formData, strategyNotes: e.target.value })
                      }
                      data-testid="input-strategy-notes"
                    />
                  </div>
                </div>
                <DialogFooter>
                  <Button
                    type="submit"
                    disabled={createOrUpdate.isPending}
                    data-testid="button-submit-subject"
                  >
                    {createOrUpdate.isPending ? "Saving..." : editingId ? "Update" : "Add"}
                  </Button>
                </DialogFooter>
              </form>
            </DialogContent>
          </Dialog>
        </div>

        {/* Overall Stats */}
        <Card className="p-6 border">
          <div className="space-y-4">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center">
                <TrendingUp className="w-6 h-6 text-primary" />
              </div>
              <div className="flex-1">
                <p className="text-sm text-muted-foreground mb-1">Average Progress</p>
                <div className="flex items-center gap-4">
                  <Progress value={averageProgress} className="flex-1 h-2" />
                  <span className="text-lg font-bold">{Math.round(averageProgress)}%</span>
                </div>
              </div>
            </div>
            <p className="text-sm text-muted-foreground">
              You're excelling as a tutor while keeping your own academics strong. Keep up the great work!
            </p>
          </div>
        </Card>

        {/* Subjects List */}
        <div className="grid md:grid-cols-2 gap-6">
          {!subjects || subjects.length === 0 ? (
            <Card className="md:col-span-2 p-12 text-center border">
              <BookOpen className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
              <p className="text-muted-foreground mb-2">
                No subjects tracked yet
              </p>
              <p className="text-sm text-muted-foreground/80">
                Add your first subject to start tracking your academic journey
              </p>
            </Card>
          ) : (
            subjects.map((subject) => {
              const current = subject.currentMark || 0;
              const progress = Math.min((current / subject.targetMark) * 100, 100);
              const isOnTrack = current >= subject.targetMark * 0.8;

              return (
                <Card
                  key={subject.id}
                  className="p-6 border space-y-4"
                  data-testid={`subject-card-${subject.id}`}
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex items-start gap-3 flex-1">
                      <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
                        <Target className="w-5 h-5 text-primary" />
                      </div>
                      <div className="flex-1">
                        <h3 className="font-semibold text-lg">{subject.subject}</h3>
                        <p className="text-sm text-muted-foreground">
                          Target: {subject.targetMark}%
                        </p>
                      </div>
                    </div>
                    <div className="flex gap-1">
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleEdit(subject)}
                        data-testid={`button-edit-${subject.id}`}
                      >
                        <Edit className="w-4 h-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => deleteSubject.mutate(subject.id)}
                        data-testid={`button-delete-${subject.id}`}
                      >
                        <Trash2 className="w-4 h-4 text-destructive" />
                      </Button>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <div className="flex items-center justify-between text-sm">
                      <span className="text-muted-foreground">Current Progress</span>
                      <span className="font-semibold">
                        {subject.currentMark || 0}/{subject.targetMark}
                      </span>
                    </div>
                    <Progress value={progress} className="h-2" />
                    <p
                      className={`text-xs font-medium ${
                        isOnTrack ? "text-green-600" : "text-amber-600"
                      }`}
                    >
                      {isOnTrack ? "On track" : "Needs attention"}
                    </p>
                  </div>

                  {subject.strategyNotes && (
                    <div className="pt-3 border-t">
                      <p className="text-sm text-muted-foreground">
                        {subject.strategyNotes}
                      </p>
                    </div>
                  )}
                </Card>
              );
            })
          )}
        </div>
      </div>
    </DashboardLayout>
  );
}

