import { Switch, Route } from "wouter";
import { QueryClientProvider } from "@tanstack/react-query";
import { queryClient } from "./lib/queryClient";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";

// General Pages
import Landing from "@/pages/landing";
import AuthPage from "@/pages/auth";
import Home from "@/pages/home";
import NotFound from "@/pages/not-found";

// Tutor Pages
import TutorPod from "@/pages/tutor/pod";
import TutorGrowth from "@/pages/tutor/growth";
import TutorAcademics from "@/pages/tutor/academics";
import TutorSessions from "@/pages/tutor/sessions";
import TutorUpdates from "@/pages/tutor/updates";

// TD Pages
import TDNoPod from "@/pages/td/no-pod";
import TDDashboard from "@/pages/td/dashboard";
import TDOverview from "@/pages/td/overview";
import TDTutors from "@/pages/td/tutors";
import TDReports from "@/pages/td/reports";
import TDUpdates from "@/pages/td/updates";

// COO Pages
import COODashboard from "@/pages/coo/dashboard";
import COOApplications from "@/pages/coo/applications";
import COOTutorApplications from "@/pages/coo/tutor-applications";
import COOPods from "@/pages/coo/pods";
import COOVerification from "@/pages/coo/verification";
import COOBroadcast from "@/pages/coo/broadcast";

function Router() {
  return (
    <Switch>
      {/* General Pages */}
      <Route path="/" component={Landing} />
      <Route path="/auth" component={AuthPage} />
      <Route path="/home" component={Home} />

      {/* Tutor Routes */}
      <Route path="/tutor/pod" component={TutorPod} />
      <Route path="/tutor/growth" component={TutorGrowth} />
      <Route path="/tutor/academics" component={TutorAcademics} />
      <Route path="/tutor/sessions" component={TutorSessions} />
      <Route path="/tutor/updates" component={TutorUpdates} />

      {/* TD Routes */}
      <Route path="/td/no-pod" component={TDNoPod} />
      <Route path="/td/dashboard" component={TDDashboard} />
      <Route path="/td/overview" component={TDOverview} />
      <Route path="/td/tutors" component={TDTutors} />
      <Route path="/td/reports" component={TDReports} />
      <Route path="/td/updates" component={TDUpdates} />

      {/* COO Routes */}
      <Route path="/coo/dashboard" component={COODashboard} />
      <Route path="/coo/applications" component={COOApplications} />
      <Route path="/coo/tutor-applications" component={COOTutorApplications} />
      <Route path="/coo/pods" component={COOPods} />
      <Route path="/coo/verification" component={COOVerification} />
      <Route path="/coo/broadcast" component={COOBroadcast} />

      {/* Catch-all */}
      <Route component={NotFound} />
    </Switch>
  );
}

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <Toaster />
        <Router />
      </TooltipProvider>
    </QueryClientProvider>
  );
}

