import { useEffect, useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Skeleton } from "@/components/ui/skeleton";
import { Calendar, Plus, Clock } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Slider } from "@/components/ui/slider";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { isUnauthorizedError } from "@/lib/authUtils";
import type { Session, Student } from "@shared/schema";
import { format } from "date-fns";

export default function TutorSessions() {
  const { isAuthenticated, isLoading: authLoading } = useAuth();
  const { toast } = useToast();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [formData, setFormData] = useState({
    studentId: "",
    duration: "120",
    notes: "",
    confidenceScoreDelta: [0],
  });

  const {
    data: sessions,
    isLoading: sessionsLoading,
    error: sessionsError,
  } = useQuery<Session[]>({
    queryKey: ["/api/tutor/sessions"],
    enabled: isAuthenticated && !authLoading,
  });

  const {
    data: students,
    isLoading: studentsLoading,
  } = useQuery<Student[]>({
    queryKey: ["/api/tutor/students"],
    enabled: isAuthenticated && !authLoading,
  });

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [isAuthenticated, authLoading, toast]);

  useEffect(() => {
    if (sessionsError && isUnauthorizedError(sessionsError)) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [sessionsError, toast]);

  const createSession = useMutation({
    mutationFn: async (data: typeof formData) => {
      await apiRequest("POST", "/api/tutor/sessions", {
        studentId: data.studentId,
        duration: parseInt(data.duration),
        notes: data.notes.trim() || null,
        confidenceScoreDelta: data.confidenceScoreDelta[0],
        date: new Date().toISOString(),
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/tutor/sessions"] });
      queryClient.invalidateQueries({ queryKey: ["/api/tutor/pod"] });
      queryClient.invalidateQueries({ queryKey: ["/api/tutor/students"] });
      setDialogOpen(false);
      setFormData({ studentId: "", duration: "120", notes: "", confidenceScoreDelta: [0] });
      toast({
        title: "Session logged",
        description: "Your session has been recorded successfully.",
      });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to log session. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.studentId || !formData.duration) {
      toast({
        title: "Validation Error",
        description: "Please select a student and duration.",
        variant: "destructive",
      });
      return;
    }
    createSession.mutate(formData);
  };

  if (authLoading || sessionsLoading || studentsLoading) {
    return (
      <DashboardLayout>
        <div className="space-y-6">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-40" />
          <Skeleton className="h-64" />
        </div>
      </DashboardLayout>
    );
  }

  const getStudentName = (studentId: string) => {
    return students?.find((s) => s.id === studentId)?.name || "Unknown";
  };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <h1 className="text-2xl md:text-3xl font-bold tracking-tight">Sessions</h1>
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button className="gap-2" data-testid="button-log-session">
                <Plus className="w-4 h-4" />
                Log Session
              </Button>
            </DialogTrigger>
            <DialogContent>
              <form onSubmit={handleSubmit}>
                <DialogHeader>
                  <DialogTitle>Log New Session</DialogTitle>
                  <DialogDescription>
                    Record a completed tutoring session with your student.
                  </DialogDescription>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div className="space-y-2">
                    <Label htmlFor="student">Student *</Label>
                    <Select
                      value={formData.studentId}
                      onValueChange={(value) =>
                        setFormData({ ...formData, studentId: value })
                      }
                    >
                      <SelectTrigger data-testid="select-student">
                        <SelectValue placeholder="Select a student" />
                      </SelectTrigger>
                      <SelectContent>
                        {students?.map((student) => (
                          <SelectItem key={student.id} value={student.id}>
                            {student.name} - Grade {student.grade}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="duration">Duration (minutes) *</Label>
                    <Input
                      id="duration"
                      type="number"
                      min="30"
                      max="240"
                      value={formData.duration}
                      onChange={(e) =>
                        setFormData({ ...formData, duration: e.target.value })
                      }
                      data-testid="input-duration"
                    />
                  </div>
                  <div className="space-y-3">
                    <div className="flex items-center justify-between">
                      <Label htmlFor="confidence">Confidence Change</Label>
                      <span className="text-sm font-bold">
                        {formData.confidenceScoreDelta[0] > 0 ? "+" : ""}
                        {formData.confidenceScoreDelta[0]}
                      </span>
                    </div>
                    <Slider
                      id="confidence"
                      min={-5}
                      max={5}
                      step={0.5}
                      value={formData.confidenceScoreDelta}
                      onValueChange={(value) =>
                        setFormData({ ...formData, confidenceScoreDelta: value })
                      }
                      className="py-4"
                      data-testid="input-confidence-delta"
                    />
                    <p className="text-xs text-muted-foreground">
                      Did the student's confidence improve or decline during this session?
                    </p>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="notes">Session Notes</Label>
                    <Textarea
                      id="notes"
                      placeholder="What did you cover? Any challenges or breakthroughs?"
                      value={formData.notes}
                      onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                      data-testid="input-notes"
                    />
                  </div>
                </div>
                <DialogFooter>
                  <Button
                    type="submit"
                    disabled={createSession.isPending}
                    data-testid="button-submit-session"
                  >
                    {createSession.isPending ? "Saving..." : "Log Session"}
                  </Button>
                </DialogFooter>
              </form>
            </DialogContent>
          </Dialog>
        </div>

        {/* Sessions Stats */}
        <div className="grid md:grid-cols-3 gap-6">
          <Card className="p-6 border">
            <div className="flex items-center justify-between mb-4">
              <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
                <Calendar className="w-5 h-5 text-primary" />
              </div>
            </div>
            <div className="space-y-1">
              <p className="text-2xl font-bold">{sessions?.length || 0}</p>
              <p className="text-sm text-muted-foreground">Total Sessions</p>
            </div>
          </Card>

          <Card className="p-6 border">
            <div className="flex items-center justify-between mb-4">
              <div className="w-10 h-10 rounded-lg bg-blue-500/10 flex items-center justify-center">
                <Clock className="w-5 h-5 text-blue-600" />
              </div>
            </div>
            <div className="space-y-1">
              <p className="text-2xl font-bold">
                {sessions?.reduce((sum, s) => sum + s.duration, 0) || 0}
              </p>
              <p className="text-sm text-muted-foreground">Total Minutes</p>
            </div>
          </Card>

          <Card className="p-6 border">
            <div className="flex items-center justify-between mb-4">
              <div className="w-10 h-10 rounded-lg bg-green-500/10 flex items-center justify-center">
                <Calendar className="w-5 h-5 text-green-600" />
              </div>
            </div>
            <div className="space-y-1">
              <p className="text-2xl font-bold">
                {sessions && sessions.length > 0
                  ? (
                      sessions.reduce((sum, s) => sum + s.duration, 0) / sessions.length
                    ).toFixed(0)
                  : 0}
              </p>
              <p className="text-sm text-muted-foreground">Avg. Duration (min)</p>
            </div>
          </Card>
        </div>

        {/* Sessions List */}
        <Card className="border">
          <div className="p-6 border-b">
            <h2 className="text-lg font-semibold">Session History</h2>
          </div>
          <div className="divide-y max-h-96 overflow-y-auto">
            {!sessions || sessions.length === 0 ? (
              <div className="p-12 text-center">
                <Calendar className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
                <p className="text-muted-foreground">No sessions logged yet</p>
              </div>
            ) : (
              sessions.map((session) => (
                <div
                  key={session.id}
                  className="p-6 space-y-3"
                  data-testid={`session-${session.id}`}
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1">
                      <h3 className="font-semibold">{getStudentName(session.studentId)}</h3>
                      <p className="text-sm text-muted-foreground">
                        {format(new Date(session.date), "MMMM d, yyyy 'at' h:mm a")}
                      </p>
                    </div>
                    <div className="flex items-center gap-4">
                      <div className="text-right">
                        <p className="text-sm font-medium">{session.duration} min</p>
                        {session.confidenceScoreDelta !== null &&
                          session.confidenceScoreDelta !== 0 && (
                            <p
                              className={`text-xs font-semibold ${
                                session.confidenceScoreDelta > 0
                                  ? "text-green-600"
                                  : "text-red-600"
                              }`}
                            >
                              {session.confidenceScoreDelta > 0 ? "+" : ""}
                              {session.confidenceScoreDelta} confidence
                            </p>
                          )}
                      </div>
                    </div>
                  </div>
                  {session.notes && (
                    <p className="text-sm text-muted-foreground leading-relaxed">
                      {session.notes}
                    </p>
                  )}
                </div>
              ))
            )}
          </div>
        </Card>
      </div>
    </DashboardLayout>
  );
}

