import { ReactNode } from "react";
import { Link, useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Home,
  Users,
  FolderKanban,
  FileCheck,
  Bell,
  LogOut,
  Menu,
  X,
  BookOpen,
  TrendingUp,
  Calendar,
  MessageSquare,
  GraduationCap,
} from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { isTutor, isTD, isCOO, getRoleName } from "@/lib/roles";
import { logout } from "@/lib/auth";
import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import type { Pod, TutorAssignment, User } from "@shared/schema";

interface NavItem {
  label: string;
  path: string;
  icon: ReactNode;
}

interface DashboardLayoutProps {
  children: ReactNode;
}

interface PodData {
  assignment: TutorAssignment & { pod: Pod };
  students: any[];
}

export function DashboardLayout({ children }: DashboardLayoutProps) {
  const { user, isAuthenticated } = useAuth();
  const [location] = useLocation();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Fetch pod data for tutors - only when user is authenticated and is a tutor
  const { data: tutorPodData } = useQuery<PodData>({
    queryKey: ["/api/tutor/pod"],
    enabled: isAuthenticated && !!user && isTutor(user),
    retry: false,
  });

  const tutorNav: NavItem[] = [
    { label: "My Pod", path: "/tutor/pod", icon: <FolderKanban className="w-5 h-5" /> },
    { label: "Growth", path: "/tutor/growth", icon: <TrendingUp className="w-5 h-5" /> },
    { label: "Academics", path: "/tutor/academics", icon: <BookOpen className="w-5 h-5" /> },
    { label: "Sessions", path: "/tutor/sessions", icon: <Calendar className="w-5 h-5" /> },
    { label: "Updates", path: "/tutor/updates", icon: <Bell className="w-5 h-5" /> },
  ];

  const tdNav: NavItem[] = [
    { label: "Pod Overview", path: "/td/overview", icon: <FolderKanban className="w-5 h-5" /> },
    { label: "Tutors", path: "/td/tutors", icon: <Users className="w-5 h-5" /> },
    { label: "Reports", path: "/td/reports", icon: <FileCheck className="w-5 h-5" /> },
    { label: "Updates", path: "/td/updates", icon: <Bell className="w-5 h-5" /> },
  ];

  const cooNav: NavItem[] = [
    { label: "Dashboard", path: "/coo/dashboard", icon: <Home className="w-5 h-5" /> },
    { label: "Tutor Applications", path: "/coo/tutor-applications", icon: <FileCheck className="w-5 h-5" /> },
    { label: "Pods", path: "/coo/pods", icon: <FolderKanban className="w-5 h-5" /> },
    { label: "Verification", path: "/coo/verification", icon: <FileCheck className="w-5 h-5" /> },
    { label: "Broadcast", path: "/coo/broadcast", icon: <MessageSquare className="w-5 h-5" /> },
  ];

  const navItems = isTutor(user)
    ? tutorNav
    : isTD(user)
    ? tdNav
    : isCOO(user)
    ? cooNav
    : [];

  const getUserFullName = (u: User | undefined): string => {
    if (!u) return "User";
    if (u.name && u.name.trim()) return u.name;
    if (u.firstName && u.lastName) return `${u.firstName} ${u.lastName}`;
    if (u.firstName) return u.firstName;
    if (u.email) return u.email.split("@")[0];
    return "User";
  };

  const getUserFirstName = (u: User | undefined): string => {
    const fullName = getUserFullName(u);
    return fullName.split(" ")[0] || "User";
  };

  const getInitials = (u: User | undefined): string => {
    if (!u) return "U";
    if (u.firstName && u.lastName) {
      return `${u.firstName[0]}${u.lastName[0]}`.toUpperCase();
    }
    if (u.name && u.name.trim()) {
      return u.name
        .split(" ")
        .map((n: string) => n[0])
        .join("")
        .toUpperCase()
        .slice(0, 2);
    }
    if (u.email) {
      return u.email[0].toUpperCase();
    }
    return "U";
  };

  const getRoleLabel = (u: User | undefined): string => {
    if (!u?.role) return "";
    return getRoleName(u.role);
  };

  const getPodLabel = () => {
    // Show pod name only when tutor has an actual pod assignment
    // Note: TDs without pods are redirected to /td/no-pod, so they won't see this header
    if (isTutor(user) && tutorPodData?.assignment?.pod) {
      return tutorPodData.assignment.pod.podName;
    }
    return "";
  };

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <header className="border-b bg-card/50 backdrop-blur-sm sticky top-0 z-50 shadow-sm">
        <div className="h-16 px-4 flex items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <Button
              variant="ghost"
              size="icon"
              className="md:hidden"
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
              data-testid="button-mobile-menu"
            >
              {mobileMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
            </Button>

            <Link href="/" className="flex items-center gap-3">
              <GraduationCap className="w-8 h-8 text-primary" />
              <div className="hidden sm:block">
                <div className="font-bold text-base tracking-tight">TT Confidence Hub</div>
                {user && (
                  <div className="text-xs text-muted-foreground">
                    {getRoleLabel(user)}
                    {getPodLabel() && ` • ${getPodLabel()}`}
                  </div>
                )}
              </div>
            </Link>
          </div>

          {/* Desktop Navigation */}
          <nav className="hidden md:flex items-center gap-1">
            {navItems.map((item) => (
              <Link key={item.path} href={item.path}>
                <Button
                  variant={location === item.path ? "default" : "ghost"}
                  size="sm"
                  className="gap-2 font-medium"
                  data-testid={`link-${item.label.toLowerCase().replace(/\s+/g, "-")}`}
                >
                  {item.icon}
                  <span>{item.label}</span>
                </Button>
              </Link>
            ))}
          </nav>

          {/* User Menu */}
          <div className="flex items-center gap-3">
            <Button
              variant="ghost"
              size="icon"
              className="relative"
              data-testid="button-notifications"
            >
              <Bell className="w-5 h-5" />
              <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-primary rounded-full"></span>
            </Button>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button
                  variant="ghost"
                  className="gap-2 hover-elevate"
                  data-testid="button-user-menu"
                >
                  <Avatar className="w-9 h-9 border-2 border-primary/20">
                    <AvatarImage src={user?.profileImageUrl || undefined} alt={getUserFullName(user)} />
                    <AvatarFallback className="bg-primary/10 text-primary font-bold text-sm">
                      {getInitials(user)}
                    </AvatarFallback>
                  </Avatar>
                  <span className="hidden sm:inline text-sm font-semibold" data-testid="text-user-first-name">{getUserFirstName(user)}</span>
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-64">
                <DropdownMenuLabel>
                  <div className="flex items-center gap-3 py-2">
                    <Avatar className="w-12 h-12 border-2 border-primary/20">
                      <AvatarImage src={user?.profileImageUrl || undefined} alt={getUserFullName(user)} />
                      <AvatarFallback className="bg-primary/10 text-primary font-bold">
                        {getInitials(user)}
                      </AvatarFallback>
                    </Avatar>
                    <div className="flex flex-col space-y-1">
                      <p className="text-sm font-semibold leading-none" data-testid="text-user-full-name">{getUserFullName(user)}</p>
                      <p className="text-xs leading-none text-muted-foreground">{user?.email}</p>
                    </div>
                  </div>
                </DropdownMenuLabel>
                <DropdownMenuSeparator />
                <div className="px-2 py-2">
                  <Badge className="bg-primary/10 text-primary border-primary/20 text-xs">
                    {user?.role ? getRoleName(user.role) : "Unknown"}
                  </Badge>
                </div>
                <DropdownMenuSeparator />
                <DropdownMenuItem
                  onClick={() => logout()}
                  className="text-destructive gap-2 font-medium"
                  data-testid="button-logout"
                >
                  <LogOut className="w-4 h-4" />
                  Log Out
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </div>

        {/* Mobile Navigation */}
        {mobileMenuOpen && (
          <nav className="md:hidden border-t bg-card px-4 py-4 space-y-1">
            {navItems.map((item) => (
              <Link key={item.path} href={item.path}>
                <Button
                  variant={location === item.path ? "default" : "ghost"}
                  className="w-full justify-start gap-2 font-medium"
                  onClick={() => setMobileMenuOpen(false)}
                  data-testid={`mobile-link-${item.label.toLowerCase().replace(/\s+/g, "-")}`}
                >
                  {item.icon}
                  <span>{item.label}</span>
                </Button>
              </Link>
            ))}
          </nav>
        )}
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto p-4 md:p-8">{children}</main>
    </div>
  );
}

