shared/schema.ts.content:
import { sql } from "drizzle-orm";
import {
  pgTable,
  varchar,
  text,
  timestamp,
  boolean,
  integer,
  jsonb,
  pgEnum,
  index,
  real,
} from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

// ============================================
// ENUMS
// ============================================

export const roleEnum = pgEnum("role", ["tutor", "td", "coo"]);
export const podTypeEnum = pgEnum("pod_type", ["training", "commercial"]);
export const phaseEnum = pgEnum("phase", ["foundation", "scale_test"]);
export const podStatusEnum = pgEnum("pod_status", ["active", "completed"]);
export const certificationStatusEnum = pgEnum("certification_status", [
  "pending",
  "passed",
  "failed",
]);
export const verificationStatusEnum = pgEnum("verification_status", [
  "pending",
  "verified",
  "rejected",
]);
export const visibilityEnum = pgEnum("visibility", ["all", "tds", "tutors"]);
export const applicationStatusEnum = pgEnum("application_status", [
  "pending",
  "approved",
  "rejected",
]);

// ============================================
// SESSION STORAGE (Required for Replit Auth)
// ============================================

export const sessions = pgTable(
  "sessions",
  {
    sid: varchar("sid").primaryKey(),
    sess: jsonb("sess").notNull(),
    expire: timestamp("expire").notNull(),
  },
  (table) => [index("IDX_session_expire").on(table.expire)]
);

// ============================================
// USERS TABLE
// ============================================

export const users = pgTable("users", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  email: varchar("email").unique().notNull(),
  firstName: varchar("first_name"),
  lastName: varchar("last_name"),
  profileImageUrl: varchar("profile_image_url"),

  // Supabase auth fields
  password: varchar("password"), // Hashed password (optional - Supabase handles auth)

  // TT-specific fields
  role: roleEnum("role").notNull().default("tutor"),
  name: varchar("name").notNull(),
  grade: varchar("grade"), // For tutors only
