import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { supabase } from "@/lib/supabaseClient";
import { useToast } from "@/hooks/use-toast";
import { useNavigate } from "react-router-dom"; // ✅ React Router hook

interface AuthFormProps {
  mode: "signup" | "login";
}

export function AuthForm({ mode }: AuthFormProps) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [role, setRole] = useState("tutor");
  const [loading, setLoading] = useState(false);
  const { toast } = useToast();
  const navigate = useNavigate(); // ✅ use React Router navigate

  const redirectByRole = (role: string) => {
    if (role === "tutor") navigate("/tutor/pod");
    else if (role === "td") navigate("/td/dashboard");
    else if (role === "coo") navigate("/coo/dashboard");
    else navigate("/");
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      let redirectUrl = "/";

      if (mode === "signup") {
        // Call backend signup endpoint
        const response = await fetch("/api/auth/signup", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body: JSON.stringify({
            email,
            password,
            role,
            first_name: firstName,
            last_name: lastName,
          }),
        });

        const data = await response.json();

        if (!response.ok) {
          throw new Error(data.message || "Signup failed");
        }

        // Sign in to Supabase on the client side to establish client session
        const { error: supabaseError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });

        if (supabaseError) {
          console.warn("Supabase client signin after signup failed:", supabaseError.message);
        }

        redirectUrl = data.redirectUrl || "/tutor/pod";

        toast({
          title: "Welcome!",
          description: "Your account has been created successfully.",
        });

        // Wait a moment for session cookie to be fully set
        await new Promise(resolve => setTimeout(resolve, 100));

        // Force page reload to ensure fresh session is loaded
        window.location.href = redirectUrl;
        return; // Exit early since we're reloading
      }

      if (mode === "login") {
        // Call backend signin endpoint
        const response = await fetch("/api/auth/signin", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body: JSON.stringify({ email, password }),
        });

        const data = await response.json();

        if (!response.ok) {
          throw new Error(data.message || "Login failed");
        }

        // Also sign in to Supabase on the client side
        const { error: supabaseError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });

        if (supabaseError) {
          console.warn("Supabase client signin failed:", supabaseError.message);
        }

        redirectUrl = data.redirectUrl || "/tutor/pod";

        toast({
          title: "Welcome back!",
          description: "You have been logged in successfully.",
        });
      }

      // Wait a moment for session cookie to be fully set
      await new Promise(resolve => setTimeout(resolve, 100));

      // Force page reload to ensure fresh session is loaded
      window.location.href = redirectUrl;
    } catch (err: any) {
      toast({
        title: "Error",
        description: err.message || "Something went wrong",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card className="w-full max-w-md">
      <CardHeader>
        <CardTitle>{mode === "signup" ? "Create Account" : "Welcome Back"}</CardTitle>
        <CardDescription>
          {mode === "signup" ? "Enter your details to get started" : "Login to your dashboard"}
        </CardDescription>
      </CardHeader>

      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          {mode === "signup" && (
            <>
              <div className="space-y-2">
                <Label htmlFor="firstName">First Name</Label>
                <Input id="firstName" type="text" placeholder="John" value={firstName} onChange={(e) => setFirstName(e.target.value)} required />
              </div>

              <div className="space-y-2">
                <Label htmlFor="lastName">Last Name</Label>
                <Input id="lastName" type="text" placeholder="Doe" value={lastName} onChange={(e) => setLastName(e.target.value)} required />
              </div>

              <div className="space-y-2">
                <Label htmlFor="role">Role</Label>
                <select id="role" value={role} onChange={(e) => setRole(e.target.value)} className="border border-gray-300 rounded-md p-2 w-full">
                  <option value="tutor">Tutor</option>
                  <option value="td">Territory Director (TD)</option>
                  <option value="coo">COO</option>
                </select>
              </div>
            </>
          )}

          <div className="space-y-2">
            <Label htmlFor="email">Email</Label>
            <Input id="email" type="email" placeholder="your@email.com" value={email} onChange={(e) => setEmail(e.target.value)} required />
          </div>

          <div className="space-y-2">
            <Label htmlFor="password">Password</Label>
            <Input id="password" type="password" placeholder="Enter your password" value={password} onChange={(e) => setPassword(e.target.value)} required minLength={6} />
          </div>

          <Button type="submit" className="w-full" disabled={loading}>
            {loading ? "Please wait..." : mode === "signup" ? "Sign Up" : "Login"}
          </Button>
        </form>
      </CardContent>
    </Card>
  );
}

