import { createClient } from "@supabase/supabase-js";
import type {
  Express,
  RequestHandler,
  Request,
  Response,
  NextFunction,
} from "express";
import session from "express-session";
import memorystore from "memorystore";
import { storage } from "./storage";

if (!process.env.SUPABASE_URL || !process.env.SUPABASE_ANON_KEY) {
  throw new Error("Missing Supabase environment variables");
}

const supabase = createClient(
  process.env.SUPABASE_URL,
  process.env.SUPABASE_ANON_KEY,
);

export function getSession() {
  const sessionTtl = 7 * 24 * 60 * 60 * 1000; // 1 week
  const MemoryStore = memorystore(session);
  const sessionStore = new MemoryStore({
    checkPeriod: sessionTtl,
  });
  return session({
    secret: process.env.SESSION_SECRET!,
    store: sessionStore,
    resave: false,
    saveUninitialized: true, // Changed to true to ensure cookie is set
    cookie: {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      sameSite: process.env.NODE_ENV === "production" ? "none" : "lax",
      maxAge: sessionTtl,
    },
  });
}

export async function setupAuth(app: Express) {
  app.set("trust proxy", 1);
  app.use(getSession());

  // Sign up endpoint
  app.post("/api/auth/signup", async (req: Request, res: Response) => {
    try {
      const { email, password, role = "tutor", first_name = "", last_name = "" } = req.body;

      if (!email || !password) {
        return res
          .status(400)
          .json({ message: "Email and password are required" });
      }

      // Create user in Supabase Auth with metadata
      const { data: authData, error: authError } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: {
            role,
            first_name,
            last_name,
          },
        },
      });

      if (authError) {
        console.error("Supabase signup error:", authError);
        return res.status(400).json({ message: authError.message });
      }

      if (!authData.user) {
        return res.status(400).json({ message: "Failed to create user" });
      }

      // Note: The Supabase trigger will automatically create the user in public.users table
      // We no longer need to manually insert here

      // Set session
      (req.session as any).userId = authData.user.id;
      (req.session as any).email = authData.user.email;
      (req.session as any).accessToken = authData.session?.access_token;

      // Wait for trigger to create user, then get from database to determine redirect
      // Retry logic for new signups (trigger needs time)
      let user = null;
      let attempts = 0;
      const maxAttempts = 5;

      while (attempts < maxAttempts && !user) {
        user = await storage.getUserByEmail(email);
        if (!user && attempts < maxAttempts - 1) {
          await new Promise(resolve => setTimeout(resolve, 500));
        }
        attempts++;
      }

      let redirectUrl = "/tutor/pod";
      if (user) {
        if (user.role === "coo") {
          redirectUrl = "/coo/dashboard";
        } else if (user.role === "td") {
          const podId = await storage.checkTDPodAssignment(user.email!);
          redirectUrl = podId ? "/td/dashboard" : "/td/no-pod";
        }
      }

      // Save session before sending response
      req.session.save((err) => {
        if (err) {
          console.error("Session save error:", err);
          return res.status(500).json({ message: "Session error" });
        }

        res.json({
          user: authData.user,
          redirectUrl,
          message: "Signup successful",
        });
      });
    } catch (error) {
      console.error("Signup error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  // Sign in endpoint
  app.post("/api/auth/signin", async (req: Request, res: Response) => {
    try {
      const { email, password } = req.body;

      if (!email || !password) {
        return res
          .status(400)
          .json({ message: "Email and password are required" });
      }

      // Authenticate with Supabase
      const { data: authData, error: authError } =
        await supabase.auth.signInWithPassword({
          email,
          password,
        });

      if (authError) {
        console.error("Supabase signin error:", authError);
        return res.status(401).json({ message: "Invalid credentials" });
      }

      if (!authData.user) {
        return res.status(401).json({ message: "Invalid credentials" });
      }

      // Get user from our database
      // ✅ Get user directly from Supabase 'users' table
      const { data: user, error: fetchError } = await supabase
        .from("users")
        .select("*")
        .eq("email", email)
        .maybeSingle();

      if (fetchError || !user) {
        console.error("User fetch error:", fetchError);
        return res.status(401).json({ message: "User not found" });
      }

      // Set session
      (req.session as any).userId = authData.user.id;
      (req.session as any).email = authData.user.email;
      (req.session as any).accessToken = authData.session?.access_token;

      console.log("💾 Setting session - Session ID:", req.sessionID);
      console.log("💾 User ID being saved:", authData.user.id);

      // Determine redirect based on role
      let redirectUrl = "/tutor/pod";
      if (user.role === "coo") {
        redirectUrl = "/coo/dashboard";
      } else if (user.role === "td") {
        const podId = await storage.checkTDPodAssignment(user.email!);
        redirectUrl = podId ? "/td/dashboard" : "/td/no-pod";
      }

      // Save session before sending response
      req.session.save((err) => {
        if (err) {
          console.error("❌ Session save error:", err);
          return res.status(500).json({ message: "Session error" });
        }

        console.log("✅ Session saved successfully for user:", user.email);

        res.json({
          user: authData.user,
          dbUser: user,
          redirectUrl,
          message: "Login successful",
        });
      });
    } catch (error) {
      console.error("Signin error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  // Logout endpoint
  app.post("/api/auth/logout", async (req: Request, res: Response) => {
    try {
      const accessToken = (req.session as any).accessToken;

      if (accessToken) {
        await supabase.auth.signOut();
      }

      req.session.destroy((err) => {
        if (err) {
          console.error("Session destruction error:", err);
        }
        res.json({ message: "Logged out successfully" });
      });
    } catch (error) {
      console.error("Logout error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  // Get current user endpoint
  app.get("/api/auth/user", async (req: Request, res: Response) => {
    try {
      console.log("🔍 Session check - Session ID:", req.sessionID);
      console.log("🔍 Session data:", req.session);
      const userId = (req.session as any).userId;
      console.log("🔍 User ID from session:", userId);

      if (!userId) {
        console.log("❌ No userId in session");
        return res.status(401).json({ message: "Unauthorized" });
      }

      const user = await storage.getUser(userId);
      if (!user) {
        console.log("❌ User not found in database for ID:", userId);
        return res.status(401).json({ message: "User not found" });
      }

      console.log("✅ User authenticated:", user.email);
      res.json(user);
    } catch (error) {
      console.error("Get user error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });
}

// Middleware to check if user is authenticated
export const isAuthenticated: RequestHandler = async (
  req: Request,
  res: Response,
  next: NextFunction,
) => {
  try {
    const userId = (req.session as any).userId;

    if (!userId) {
      return res.status(401).json({ message: "Unauthorized" });
    }

    // Get user from database and attach to request
    const user = await storage.getUser(userId);
    if (!user) {
      return res.status(401).json({ message: "Unauthorized" });
    }

    (req as any).dbUser = user;
    next();
  } catch (error) {
    console.error("Auth middleware error:", error);
    res.status(401).json({ message: "Unauthorized" });
  }
};

