import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Skeleton } from "@/components/ui/skeleton";
import { CheckCircle, XCircle, FileText, Clock, User } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { TutorApplication } from "@shared/schema";
import { format } from "date-fns";

export default function TutorApplicationsPage() {
  const { toast } = useToast();
  const [selectedApplication, setSelectedApplication] = useState<TutorApplication | null>(null);
  const [showRejectDialog, setShowRejectDialog] = useState(false);
  const [rejectionReason, setRejectionReason] = useState("");

  const { data: applications, isLoading } = useQuery<TutorApplication[]>({
    queryKey: ["/api/coo/tutor-applications"],
  });

  const approveMutation = useMutation({
    mutationFn: (id: string) => apiRequest("POST", `/api/coo/tutor-applications/${id}/approve`, {}),
    onSuccess: () => {
      toast({
        title: "Application Approved",
        description: "The tutor application has been approved successfully.",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/coo/tutor-applications"] });
      setSelectedApplication(null);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to approve application",
        variant: "destructive",
      });
    },
  });

  const rejectMutation = useMutation({
    mutationFn: ({ id, reason }: { id: string; reason: string }) =>
      apiRequest("POST", `/api/coo/tutor-applications/${id}/reject`, { reason }),
    onSuccess: () => {
      toast({
        title: "Application Rejected",
        description: "The tutor application has been rejected.",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/coo/tutor-applications"] });
      setSelectedApplication(null);
      setShowRejectDialog(false);
      setRejectionReason("");
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to reject application",
        variant: "destructive",
      });
    },
  });

  const handleApprove = (application: TutorApplication) => {
    approveMutation.mutate(application.id);
  };

  const handleReject = () => {
    if (selectedApplication && rejectionReason.trim()) {
      rejectMutation.mutate({ id: selectedApplication.id, reason: rejectionReason });
    }
  };

  const pendingApplications = applications?.filter((app) => app.status === "pending") || [];
  const approvedApplications = applications?.filter((app) => app.status === "approved") || [];
  const rejectedApplications = applications?.filter((app) => app.status === "rejected") || [];

  if (isLoading) {
    return (
      <DashboardLayout>
        <div className="space-y-6">
          <Skeleton className="h-12 w-64" />
          <Skeleton className="h-96" />
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Tutor Applications</h1>
          <p className="text-muted-foreground">Review and manage tutor applications</p>
        </div>

        <Tabs defaultValue="pending" className="w-full">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="pending" className="gap-2" data-testid="tab-pending">
              <Clock className="w-4 h-4" />
              Pending ({pendingApplications.length})
            </TabsTrigger>
            <TabsTrigger value="approved" className="gap-2" data-testid="tab-approved">
              <CheckCircle className="w-4 h-4" />
              Approved ({approvedApplications.length})
            </TabsTrigger>
            <TabsTrigger value="rejected" className="gap-2" data-testid="tab-rejected">
              <XCircle className="w-4 h-4" />
              Rejected ({rejectedApplications.length})
            </TabsTrigger>
          </TabsList>

          <TabsContent value="pending" className="space-y-4">
            {pendingApplications.length === 0 ? (
              <Card className="p-12 text-center">
                <FileText className="w-16 h-16 mx-auto mb-4 text-muted-foreground" />
                <p className="text-muted-foreground">No pending applications</p>
              </Card>
            ) : (
              pendingApplications.map((application) => (
                <ApplicationCard
                  key={application.id}
                  application={application}
                  onApprove={() => handleApprove(application)}
                  onReject={() => {
                    setSelectedApplication(application);
                    setShowRejectDialog(true);
                  }}
                  onViewDetails={() => setSelectedApplication(application)}
                />
              ))
            )}
          </TabsContent>

          <TabsContent value="approved" className="space-y-4">
            {approvedApplications.length === 0 ? (
              <Card className="p-12 text-center">
                <FileText className="w-16 h-16 mx-auto mb-4 text-muted-foreground" />
                <p className="text-muted-foreground">No approved applications</p>
              </Card>
            ) : (
              approvedApplications.map((application) => (
                <ApplicationCard
                  key={application.id}
                  application={application}
                  onViewDetails={() => setSelectedApplication(application)}
                  showActions={false}
                />
              ))
            )}
          </TabsContent>

          <TabsContent value="rejected" className="space-y-4">
            {rejectedApplications.length === 0 ? (
              <Card className="p-12 text-center">
                <FileText className="w-16 h-16 mx-auto mb-4 text-muted-foreground" />
                <p className="text-muted-foreground">No rejected applications</p>
              </Card>
            ) : (
              rejectedApplications.map((application) => (
                <ApplicationCard
                  key={application.id}
                  application={application}
                  onViewDetails={() => setSelectedApplication(application)}
                  showActions={false}
                />
              ))
            )}
          </TabsContent>
        </Tabs>

        {/* Application Details Dialog */}
        {selectedApplication && !showRejectDialog && (
          <Dialog open={!!selectedApplication} onOpenChange={() => setSelectedApplication(null)}>
            <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle>{selectedApplication.fullNames}</DialogTitle>
                <DialogDescription>Submitted on {format(new Date(selectedApplication.createdAt), "PPP")}</DialogDescription>
              </DialogHeader>
              <ApplicationDetails application={selectedApplication} />
              {selectedApplication.status === "pending" && (
                <DialogFooter className="gap-2">
                  <Button
                    variant="outline"
                    onClick={() => {
                      setShowRejectDialog(true);
                    }}
                    data-testid="button-reject-application"
                  >
                    <XCircle className="w-4 h-4 mr-2" />
                    Reject
                  </Button>
                  <Button
                    onClick={() => handleApprove(selectedApplication)}
                    disabled={approveMutation.isPending}
                    data-testid="button-approve-application"
                  >
                    <CheckCircle className="w-4 h-4 mr-2" />
                    {approveMutation.isPending ? "Approving..." : "Approve"}
                  </Button>
                </DialogFooter>
              )}
            </DialogContent>
          </Dialog>
        )}

        {/* Reject Dialog */}
        <Dialog open={showRejectDialog} onOpenChange={setShowRejectDialog}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Reject Application</DialogTitle>
              <DialogDescription>Please provide a reason for rejecting this application.</DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="reason">Rejection Reason</Label>
                <Textarea
                  id="reason"
                  value={rejectionReason}
                  onChange={(e) => setRejectionReason(e.target.value)}
                  placeholder="Enter the reason for rejection..."
                  rows={4}
                  data-testid="input-rejection-reason"
                />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setShowRejectDialog(false)}>
                Cancel
              </Button>
              <Button
                variant="destructive"
                onClick={handleReject}
                disabled={!rejectionReason.trim() || rejectMutation.isPending}
                data-testid="button-confirm-reject"
              >
                {rejectMutation.isPending ? "Rejecting..." : "Reject Application"}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </DashboardLayout>
  );
}

function ApplicationCard({
  application,
  onApprove,
  onReject,
  onViewDetails,
  showActions = true,
}: {
  application: TutorApplication;
  onApprove?: () => void;
  onReject?: () => void;
  onViewDetails: () => void;
  showActions?: boolean;
}) {
  const statusColors = {
    pending: "bg-amber-100 text-amber-800 border-amber-200",
    approved: "bg-green-100 text-green-800 border-green-200",
    rejected: "bg-red-100 text-red-800 border-red-200",
  };

  return (
    <Card data-testid={`application-card-${application.id}`}>
      <CardHeader>
        <div className="flex items-start justify-between">
          <div className="space-y-1">
            <CardTitle className="text-xl">{application.fullNames}</CardTitle>
            <CardDescription>
              {application.email} • {application.phoneNumber}
            </CardDescription>
          </div>
          <Badge className={statusColors[application.status]}>{application.status.toUpperCase()}</Badge>
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
          <div>
            <p className="text-muted-foreground">Age</p>
            <p className="font-medium">{application.age}</p>
          </div>
          <div>
            <p className="text-muted-foreground">Location</p>
            <p className="font-medium">{application.city}</p>
          </div>
          <div>
            <p className="text-muted-foreground">Status</p>
            <p className="font-medium">{((application as any).current_status || application.currentStatus || "N/A").replace(/_/g, " ")}</p>
          </div>
          <div>
            <p className="text-muted-foreground">Grades</p>
            <p className="font-medium">{((application as any).grades_equipped || application.gradesEquipped || []).join(", ")}</p>
          </div>
        </div>

        <div className="flex gap-2">
          <Button variant="outline" onClick={onViewDetails} data-testid="button-view-details">
            <User className="w-4 h-4 mr-2" />
            View Full Application
          </Button>
          {showActions && onApprove && onReject && (
            <>
              <Button variant="outline" onClick={onReject} data-testid="button-reject">
                <XCircle className="w-4 h-4 mr-2" />
                Reject
              </Button>
              <Button onClick={onApprove} data-testid="button-approve">
                <CheckCircle className="w-4 h-4 mr-2" />
                Approve
              </Button>
            </>
          )}
        </div>

        {application.status === "rejected" && application.rejectionReason && (
          <div className="bg-red-50 dark:bg-red-950 p-3 rounded-md border border-red-200 dark:border-red-800">
            <p className="text-sm font-medium text-red-900 dark:text-red-100">Rejection Reason:</p>
            <p className="text-sm text-red-700 dark:text-red-300">{application.rejectionReason}</p>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

function ApplicationDetails({ application }: { application: TutorApplication }) {
  const mindset = application.mindsetData as any;
  const psychological = application.psychologicalData as any;
  const vision = application.visionData as any;
  const toolConfidence = application.toolConfidence as any;

  return (
    <div className="space-y-6">
      <Section title="Personal Information">
        <InfoItem label="Full Names" value={application.fullNames} />
        <InfoItem label="Age" value={application.age.toString()} />
        <InfoItem label="Email" value={application.email} />
        <InfoItem label="Phone" value={application.phoneNumber} />
        <InfoItem label="City" value={application.city} />
        <InfoItem label="Current Status" value={application.currentStatus.replace(/_/g, " ")} />
        <InfoItem label="Who Influences You" value={application.whoInfluences || "Not provided"} />
        <InfoItem label="Environment" value={application.environment || "Not provided"} />
      </Section>

      <Section title="Mindset & Mission">
        <InfoItem label="Why Tutor?" value={mindset?.whyTutor} />
        <InfoItem label="Confidence Mentor Understanding" value={mindset?.whatIsConfidenceMentor} />
        <InfoItem label="Resilience Story" value={mindset?.resilienceStory} />
        <InfoItem label="Reaction to Struggling Student" value={mindset?.reactionToStudent} />
        <InfoItem label="Belief in Confidence" value={mindset?.beliefInConfidence} />
        <InfoItem label="Pressure Weakness" value={mindset?.pressureWeak} />
        <InfoItem label="Motivation Type" value={mindset?.motivationQuote} />
      </Section>

      <Section title="Academic Confidence">
        <InfoItem label="Grades Equipped" value={application.gradesEquipped.join(", ")} />
        <InfoItem label="Can Explain Clearly" value={application.canExplainClearly.replace(/_/g, " ")} />
        <InfoItem label="Google Meet Confidence" value={`${toolConfidence?.googleMeet || 0}/5`} />
        <InfoItem label="OneNote Confidence" value={`${toolConfidence?.onenote || 0}/5`} />
        <InfoItem label="Screen Share Confidence" value={`${toolConfidence?.screenShare || 0}/5`} />
        <InfoItem label="Student Not Improving Response" value={application.studentNotImproving?.replace(/_/g, " ")} />
      </Section>

      <Section title="Psychological Fit">
        <InfoItem label="Statement That Hits Hardest" value={psychological?.statementHits?.replace(/_/g, " ")} />
        <InfoItem label="Feedback Response" value={psychological?.feedbackResponse?.replace(/_/g, " ")} />
        <InfoItem label="Quit Reason" value={psychological?.quitReason?.replace(/_/g, " ")} />
        <InfoItem label="Team Meaning" value={psychological?.teamMeaning?.replace(/_/g, " ")} />
        <InfoItem label="What Scares You" value={psychological?.whatScares} />
      </Section>

      <Section title="Vision & Long-Term">
        <InfoItem label="Future Personality" value={vision?.futurePersonality} />
        <InfoItem label="Earnings Use" value={vision?.earningsUse} />
        <InfoItem label="Student Remembrance" value={vision?.studentRemembrance} />
        <InfoItem label="Impact vs Scale" value={vision?.impactVsScale?.replace(/_/g, " ")} />
        <InfoItem label="Reasoning" value={vision?.impactVsScaleReason} />
      </Section>

      <Section title="Availability & Commitment">
        <InfoItem label="Bootcamp Available" value={application.bootcampAvailable} />
        <InfoItem label="Commit to Trial" value={application.commitToTrial ? "Yes" : "No"} />
        <InfoItem label="Referral Source" value={application.referralSource || "Not provided"} />
        {application.videoUrl && <InfoItem label="Video URL" value={application.videoUrl} link />}
      </Section>
    </div>
  );
}

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <div className="space-y-3">
      <h3 className="text-lg font-semibold">{title}</h3>
      <div className="space-y-2 pl-4 border-l-2 border-primary/20">{children}</div>
    </div>
  );
}

function InfoItem({ label, value, link }: { label: string; value?: string; link?: boolean }) {
  if (!value) return null;

  return (
    <div className="space-y-1">
      <p className="text-sm font-medium text-muted-foreground">{label}</p>
      {link ? (
        <a href={value} target="_blank" rel="noopener noreferrer" className="text-sm text-primary hover:underline">
          {value}
        </a>
      ) : (
        <p className="text-sm">{value}</p>
      )}
    </div>
  );
}

